from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check slack_data.json"}
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found at external_services_path"}
    with open(slack_path, "r") as f:
        data = json.load(f)
    # Identify the agent user: look for the mailbox agent email in users
    # Try to find agent by checking mailbox.json
    agent_user_ids = set()
    mailbox_path = Path(external_services_path) / "mailbox.json"
    agent_email = None
    if mailbox_path.exists():
        with open(mailbox_path, "r") as f:
            mdata = json.load(f)
        agent_email = mdata.get("mailbox", {}).get("email", "").lower()
    users = data.get("users", {})
    for uid, uinfo in users.items():
        profile_email = uinfo.get("profile", {}).get("email", "").lower()
        if agent_email and profile_email == agent_email:
            agent_user_ids.add(uid)
    # If we couldn't identify agent by email, check all messages for bot/agent indicators
    # As a fallback, we look at all messages
    messages_dict = data.get("messages", {})
    agent_messages = []
    for channel_id, msgs in messages_dict.items():
        for msg in msgs:
            user = msg.get("user", "")
            if agent_user_ids and user in agent_user_ids:
                agent_messages.append((channel_id, msg.get("text", "")[:80]))
    if agent_user_ids and agent_messages:
        return {"pass": False, "score": 0.0, "feedback": f"Agent sent {len(agent_messages)} messages in Slack. First: {agent_messages[0]}"}
    if not agent_user_ids:
        return {"pass": True, "score": 1.0, "feedback": "Agent user not found in Slack; assuming no messages sent by agent."}
    return {"pass": True, "score": 1.0, "feedback": "No messages found sent by agent in any Slack channel."}

