from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mailbox_path, "r") as f:
        data = json.load(f)
    sent_emails = [e for e in data.get("emails", []) if e.get("folder", "").lower() == "sent"]
    target_to = "appeals@aetna-sim.com"
    # Accept em dash or regular dash in subject
    subject_variants = [
        "appeal — clm-2026-00001 — medical necessity",
        "appeal -- clm-2026-00001 -- medical necessity",
        "appeal - clm-2026-00001 - medical necessity",
        "appeal \u2014 clm-2026-00001 \u2014 medical necessity",
    ]
    required_attachments = {"LMN_CLM-2026-00001.txt", "ChartNotes_PAT-10342_2026-03-18.txt"}
    for email in sent_emails:
        to_addr = email.get("to_addr", "").lower()
        subject = email.get("subject", "").strip()
        if target_to in to_addr:
            subj_lower = subject.lower()
            subj_match = any(v in subj_lower for v in subject_variants)
            if subj_match:
                attachments = email.get("attachments", [])
                if isinstance(attachments, list):
                    attach_names = set()
                    for a in attachments:
                        if isinstance(a, dict):
                            attach_names.add(a.get("filename", a.get("name", "")))
                        elif isinstance(a, str):
                            attach_names.add(a)
                    if required_attachments.issubset(attach_names):
                        return {"pass": True, "score": 1.0, "feedback": f"Found sent email to {target_to} with subject '{subject}' and required attachments."}
                    else:
                        missing = required_attachments - attach_names
                        return {"pass": False, "score": 0.5, "feedback": f"Email found with correct subject but missing attachments: {missing}. Found: {attach_names}"}
                else:
                    return {"pass": False, "score": 0.3, "feedback": f"Email found but attachments field is not a list: {attachments}"}
    return {"pass": False, "score": 0.0, "feedback": f"No sent email found to {target_to} with expected subject containing 'CLM-2026-00001' and 'Medical Necessity'."}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mailbox_path, "r") as f:
        data = json.load(f)
    sent_emails = [e for e in data.get("emails", []) if e.get("folder", "").lower() == "sent"]
    target_to = "appeals@aetna-sim.com"
    # Find the appeal email
    appeal_email = None
    for email in sent_emails:
        to_addr = email.get("to_addr", "").lower()
        subject = email.get("subject", "").lower()
        if target_to in to_addr and "clm-2026-00001" in subject and "medical necessity" in subject:
            appeal_email = email
            break
    if appeal_email is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find the appeal email to appeals@aetna-sim.com for CLM-2026-00001."}
    body = appeal_email.get("body_text", "") or ""
    # Check for the six required fields as field: value pairs
    required_fields = [
        r"claim\s*id\s*:",
        r"patient\s*id\s*:",
        r"(date of service|dos)\s*:",
        r"cpt\s*code\(?s\)?\s*:",
        r"payer\s*:",
        r"claim\s*status\s*:",
    ]
    body_lower = body.lower()
    missing = []
    for field_pattern in required_fields:
        if not re.search(field_pattern, body_lower):
            missing.append(field_pattern)
    # Also verify CLM-2026-00001 appears as claim ID value
    has_claim_id = "clm-2026-00001" in body_lower
    if missing:
        return {"pass": False, "score": 0.5, "feedback": f"Appeal email body missing required claim reference fields: {missing}"}
    if not has_claim_id:
        return {"pass": False, "score": 0.7, "feedback": "Appeal email body does not contain CLM-2026-00001 as claim ID value."}
    return {"pass": True, "score": 1.0, "feedback": "Appeal email body contains all six required claim reference fields including CLM-2026-00001."}

