        (None, True),
        (7, False),
        (None, True),
        (None, True),
        ("CLM-2026-00003", False),
    ]
    mismatches = []
    for i, (exp_val, is_blank) in enumerate(expected):
        col_idx = i + 1
        cell_val = target_row[col_idx].value
