        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mailbox_path, "r", encoding="utf-8") as f:
        data = json.load(f)

    target = "catherine.lawson@pathfinder.med"
    sent_emails = [e for e in data.get("emails", []) if e.get("folder", "").lower() == "sent"]

    esc_emails = [
        e for e in sent_emails
        if target in e.get("to_addr", "").lower()
        and any(kw in e.get("subject", "").lower()
                for kw in ["esc-00001", "escalation", "high priority", "follow-up", "follow up"])
    ]

    if len(esc_emails) == 0:
        return {"pass": False, "score": 0.0,
                "feedback": "No ESC-00001 follow-up email found sent to Catherine Lawson."}
    if len(esc_emails) > 1:
        return {"pass": False, "score": 0.0,
                "feedback": f"Expected exactly 1 ESC-00001 follow-up to Catherine, found {len(esc_emails)}."}

    email = esc_emails[0]
    subject = email.get("subject", "").strip()
    body = (email.get("body_text", "") or "").lower()

    subject_ok = "esc-00001" in subject.lower() and "escalation" in subject.lower() and "high priority" in subject.lower()
    no_confirm_ok = any(p in body for p in ["no confirmation", "not yet received", "have not received", "haven't received", "no email confirmation"])
    request_ok = any(p in body for p in ["please confirm", "confirm receipt", "acknowledge", "confirmation"])

    issues = []
    if not subject_ok:
        issues.append(f"Subject '{subject}' does not match expected 'HIGH PRIORITY - Escalation Follow-Up - ESC-00001'")
    if not no_confirm_ok:
        issues.append("Body does not state that no email confirmation has been received")
    if not request_ok:
        issues.append("Body does not explicitly request confirmation or acknowledgment from Catherine")

    if issues:
